sql:
SELECT model_accuracy
FROM crime_prediction_models
WHERE model_accuracy = (
    SELECT MAX(model_accuracy)
    FROM crime_prediction_models
);

SELECT model_name
FROM crime_prediction_models
WHERE model_accuracy > (SELECT AVG(model_accuracy) FROM crime_prediction_models);

SELECT COUNT(report_id) 
FROM crime_incident_reports
WHERE report_status = 'submitted';

SELECT COUNT(*) 
FROM crime_data_exports
WHERE user_id = 1;

SELECT officer_name, badge_number
FROM crime_incident_officers
WHERE rank = 'Sergeant';

SELECT crime_type_name, description, crime_category
FROM crime_types
ORDER BY crime_type_name ASC;

SELECT report_id, report_date
FROM crime_incident_reports
WHERE report_status = 'approved';

